import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import Breadcrumb from "@components/common/breadcrumb";
// import MoveForward from "@components/common/move-forward";
import Seo from "@components/seo";
import PortfolioScreen from "@screens/matrimony-clone/portfolioscreen";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const MatrimonyClone = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Matrimony Clone Script", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.matrimonyCloneScriptImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const location = useLocation();

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Matrimony clone script is a pre-built matchmaker system that has customizable profile, search, communication, and secure user control.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1673",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a Matrimony Clone Script?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A Matrimony Clone Script is a pre-written matchmaking software that enables you to easily start a customizable online matrimony business.",
            },
          },
          {
            "@type": "Question",
            name: "How to choose a reliable matrimony clone script?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Select a good Matrimony clone script that has good security, customization features, mobile application, search engine optimization, payment and technical support.",
            },
          },
          {
            "@type": "Question",
            name: "Is the platform secure and scalable?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, a quality Matrimony clone script is secure and can be scaled in case it is constructed with a good level of security and streamlined architecture coupled with frequent upgrades.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <PortfolioScreen db={db} />
      {/* <MoveForward db={db} /> */}
    </Layout_v2>
  );
};

export default MatrimonyClone;

export const queryData = graphql`
  query MyQuery {
    matrimonyCloneScriptImg: file(
      relativePath: { eq: "matrimony-clone-script.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "matrimony-clone-script" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
